#include<bits/stdc++.h>
using namespace std;
long long a[400010],s[400010];
int main()
{
    long long t;
    scanf("%lld",&t);
    while(t--)
    {
        long long n,m;
        scanf("%lld%lld",&n,&m);
        for(long long i=1;i<=n;i++)
        {
            scanf("%lld",&a[i]);
            a[i]%=m;
        }
        sort(a+1,a+1+n);
        for(long long i=1;i<=n;i++)
        {
            s[i]=s[i-1]+a[i];
            a[i+n]=a[i]+m;
        }
        for(long long i=n+1;i<=n*2;i++)
        {
            s[i]=s[i-1]+a[i];
        }
        long long ans=LLONG_MAX;
        for(long long l=1,r=n;r<=n*2;l++,r++)
        {
            long long mid=(l+r)/2;
            ans=min(ans,(mid-l)*a[mid]-(s[mid-1]-s[l-1])+(s[r]-s[mid])-a[mid]*(r-mid));
        }
        printf("%lld\n",ans);
    }
    return 0;
}
